'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes } from 'react'
import styles from './separator.module.css'

export interface SeparatorProps extends HTMLAttributes<HTMLElement> {
  orientation?: 'horizontal' | 'vertical'
  decorative?: boolean
}

export function Separator({
  orientation = 'horizontal',
  decorative = false,
  className,
  ...props
}: SeparatorProps) {
  if (orientation === 'horizontal' && !decorative) {
    return (
      <hr data-orientation="horizontal" className={cn(styles['separator'], className)} {...props} />
    )
  }

  return (
    <div
      role={decorative ? 'none' : 'separator'}
      aria-orientation={decorative ? undefined : orientation}
      data-orientation={orientation}
      className={cn(styles['separator'], className)}
      {...props}
    />
  )
}

@layer cascivo.component {
  .separator {
    margin: 0;
    border: none;
    background-color: var(--cascivo-color-border);
    flex-shrink: 0;

    &[data-orientation='horizontal'] {
      block-size: 1px;
      inline-size: 100%;
    }

    &[data-orientation='vertical'] {
      inline-size: 1px;
      block-size: 100%;
      align-self: stretch;
    }
  }
}
